arguments.argument:
if global.gamePaused=false
{
  if oGateF_GravControl.lowGravOn=0
  {
    image_index=0
  }
  else
  {
    //Animate
    animate+=1
    if animate>=1 and animate<=10 {image_index=1}
    else if animate>=11 and animate<=20 {image_index=2}
    if animate>=21
    {
      image_index=3
      if animate>=30 {animate=0}
    }
  }
}
